from transformers import Qwen3VLForConditionalGeneration, AutoProcessor

model_name = "Qwen/Qwen3-VL-2B-Instruct"
processor = AutoProcessor.from_pretrained(model_name)
model = Qwen3VLForConditionalGeneration.from_pretrained(
    model_name, torch_dtype="auto", device_map="auto"
)

messages = [
    {"role": "system", "content": "You are a helpful visual assistant."},
    {"role": "user", "content": [
        {"type": "image", "image": "https://example.com/photo.jpg"},
        {"type": "text", "text": "Describe what you see in this image."}
    ]}
]

text = processor.apply_chat_template(
    messages, tokenize=False, add_generation_prompt=True
)
inputs = processor(
    text=text, images=["https://example.com/photo.jpg"],
    return_tensors="pt"
).to(model.device)

output = model.generate(**inputs, max_new_tokens=200)
response = processor.batch_decode(
    output[:, inputs["input_ids"].shape[1]:],
    skip_special_tokens=True
)[0]
print(response)

from PIL import Image
from transformers import Qwen3VLForConditionalGeneration, AutoProcessor

processor = AutoProcessor.from_pretrained("Qwen/Qwen3-VL-2B-Instruct")
model = Qwen3VLForConditionalGeneration.from_pretrained(
    "Qwen/Qwen3-VL-2B-Instruct", torch_dtype="auto", device_map="auto"
)

img = Image.open("dashboard_screenshot.png")

messages = [
    {"role": "user", "content": [
        {"type": "image", "image": img},
        {"type": "text", "text": "Extract all text and numbers from this screenshot."}
    ]}
]

text = processor.apply_chat_template(
    messages, tokenize=False, add_generation_prompt=True
)
inputs = processor(
    text=text, images=[img], return_tensors="pt"
).to(model.device)

output = model.generate(
    **inputs, max_new_tokens=300,
    temperature=0.3, repetition_penalty=1.1
)
result = processor.batch_decode(
    output[:, inputs["input_ids"].shape[1]:],
    skip_special_tokens=True
)[0]
print(result)
